904: // Simple ABI wrapper for initialize allocated memory.
905: export fn lex_state_init(state: *anyopaque) void {
906:     // Ensure the allocated memory is aligned.
907:     assert(@intFromPtr(state) % @alignOf(State) == 0);
908: 
909:     const s: *State = @ptrCast(@alignCast(state));
910:     s.init();
911: }
