494:     // Append literal character when possible. Then inclease the buffer_length.
495:     fn append_literal(self: *State, c: u8) void {
496:         // Only allow a-zA-Z.
497:         assert(std.ascii.isAlphabetic(c));
498: 
499:         // Check if we can add new span for input character.
500:         if (self.buffer_length < self.buffer_effective.len) {
501:             // Add character to span.
502:             self.buffer_effective[self.buffer_length] = Span.init(c);
503:         }
504:         // Increase the buffer length for tracking, we will need it went handling backspace.
505:         self.buffer_length = self.buffer_length + 1;
506:     }
507: 
508:     fn backspace(self: *State) void {
509:         // buffer_length must be positive for backspace.
510:         assert(self.buffer_length > 0);
511: 
512:         // Input mode must be either .literal or .telex.
513:         assert(self.mode == .literal or self.mode == .telex);
514: 
515:         if (self.literal_index) |literal_index| {
516:             // Input mode must be .telex when literal_index is set.
517:             assert(self.mode == .telex);
518:             // literal_index must be within buffer range when set.
519:             assert(literal_index < self.buffer_length);
520:         }
521: 
522:         // decrease the buffer_length to match the backspace.
523:         self.buffer_length -= 1;
524:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
525:         self.buffer_modification_index = null;
526:         // if the literal_index is out of buffer range, unset it.
527:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
528:             self.literal_index = null;
529:         }
530:     }
531: };
