533: test "expect State.add handles non-Telex characters less than buffer_effective range" {
534:     // Arrange
535:     var state: State = undefined;
536:     state.init();
537:     state.mode = .telex;
538: 
539:     const input_sequence = "bbbbbqqqqq";
540: 
541:     // Act
